let yes = 0, no = 0, time = 6;

while (true) {
if (chat.message == "poll-mapreset") {
say.Chat("mapreset? y/n")
while (time - 0.1 > 0) {
if (chat.message == "y" || chat.message == "yes") {
yes++;
   } else {
if (chat.message == "n" || chat.message == "no") {
no++;
   }
  if (yes > no) {
   50x.mapreset
   }
  }
 }
}


```

